// Quebra a janela em N requests de 1 dia, contornando o timeout 524 da UTMify.
// Lê DIAS_BUSCA, TMX_TOKEN, OFFER_ID, UTMIFY_DASHBOARD_ID do node Config.

const config = $('⚙️ Config').first().json;
const token = $json.auth.token;
const dias = Number(config.DIAS_BUSCA) || 30;

const agora = new Date();
const inicio = new Date(agora);
inicio.setUTCDate(inicio.getUTCDate() - dias);
inicio.setUTCHours(0, 0, 0, 0);

const janelas = [];
let cursor = new Date(inicio);
while (cursor < agora) {
  const fim = new Date(cursor);
  fim.setUTCDate(fim.getUTCDate() + 1);
  janelas.push({
    json: {
      _utmifyToken: token,
      _dashboardId: config.UTMIFY_DASHBOARD_ID,
      _tmxApiUrl: config.TMX_API_URL,
      _tmxToken: config.TMX_TOKEN,
      _offerId: config.OFFER_ID,
      dateFrom: cursor.toISOString(),
      dateTo: (fim > agora ? agora : fim).toISOString(),
      _date: cursor.toISOString().slice(0, 10),
      _janela: janelas.length + 1,
    },
  });
  cursor.setUTCDate(cursor.getUTCDate() + 1);
}
return janelas;

// Pega o array de results de cada janela diária e devolve UM snapshot por dia,
// no formato que o TMX HUB aceita em /v1/offers/:id/ingest.
//
// O endpoint UTMify /orders/search-objects retorna campos diferentes dependendo
// da versão da plataforma. Este transform tenta vários nomes — se o seu retorno
// trouxer um campo com nome diferente, é só adicionar à lista de fallbacks.

function num(v) {
  if (v === null || v === undefined || v === '') return 0;
  const n = Number(v);
  return Number.isFinite(n) ? n : 0;
}

// Safely read multiple potential field names. Returns the first numeric > 0,
// or 0 if none. UTMify spend is in CENTS — divide /100 to get BRL.
function pickCents(item, names) {
  for (const k of names) if (num(item[k]) > 0) return num(item[k]);
  return 0;
}
function pickInt(item, names) {
  for (const k of names) if (num(item[k]) > 0) return num(item[k]);
  return 0;
}

const items = $input.all();
const byDate = new Map();

let config = null;
for (const it of items) {
  if (it.json && it.json._date) {
    config = it.json;
    break;
  }
}
if (!config) {
  // First item failed; pull from the windows node.
  const win = $('📅 Quebrar em janelas diárias').first().json;
  config = win;
}

for (const it of items) {
  // Skip outright errors.
  if (it.json && (it.json.error || it.json.errorMessage)) continue;

  const date =
    it.json._date ||
    (it.json && (it.json.dateFrom || '').slice(0, 10));
  if (!date) continue;

  const results = (it.json && it.json.results) || [];
  if (!byDate.has(date)) {
    byDate.set(date, {
      date,
      spend: 0,
      sales: 0,
      revenue: 0,
      ic: 0,
      impressions: 0,
      clicks: 0,
      adsets: [],
    });
  }
  const day = byDate.get(date);

  for (const r of results) {
    const spendCents = pickCents(r, ['spend', 'spendCents', 'spendInCents', 'amountSpent']);
    const revenueCents = pickCents(r, ['revenue', 'revenueCents', 'profit', 'profitCents', 'grossRevenue', 'totalRevenue']);
    const sales = pickInt(r, ['salesCount', 'sales', 'frontSalesCount', 'orderCount', 'orders', 'purchaseCount', 'purchases']);
    const ic = pickInt(r, ['initiateCheckoutCount', 'initiateCheckout', 'initiate_checkout', 'icCount']);
    const impressions = pickInt(r, ['impressions']);
    const clicks = pickInt(r, ['inlineLinkClicks', 'clicks', 'linkClicks']);

    const adset = {
      name: String(r.name || r.adsetName || '(sem nome)').slice(0, 200),
      spend: spendCents / 100,
      revenue: revenueCents / 100,
      sales,
      ic,
    };
    if (impressions) adset.impressions = impressions;
    if (clicks) adset.clicks = clicks;
    day.adsets.push(adset);

    day.spend += adset.spend;
    day.revenue += adset.revenue;
    day.sales += sales;
    day.ic += ic;
    day.impressions += impressions;
    day.clicks += clicks;
  }
}

const snapshots = Array.from(byDate.values()).map((d) => {
  // Strip impressions/clicks if zero — schema accepts them as optional.
  if (d.impressions === 0) delete d.impressions;
  if (d.clicks === 0) delete d.clicks;
  if (!d.adsets || d.adsets.length === 0) delete d.adsets;
  return d;
});

if (snapshots.length === 0) {
  return [{ json: { _empty: true, _config: config } }];
}

return [
  {
    json: {
      _tmxApiUrl: config._tmxApiUrl,
      _tmxToken: config._tmxToken,
      _offerId: config._offerId,
      payload: { snapshots },
    },
  },
];

const r = $json;
const when = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });
console.log('[' + when + '] ✅ TMX ingest', { ingested: r.ingested, dates: r.dates });
return { json: { status: 'ok', when, ...r } };
